// Native 'Webinar: Get All' returns ONE item per webinar.
// Pull webinarKey + organizerKey (so attendees/registrants need no manual key) + subject/date/region.
function regionFromText(t) {
  const s = String(t || '').toLowerCase();
  if (/\b(uk|u\.k\.|united kingdom|england|scotland|wales|ireland|irish|dublin)\b/.test(s)) return 'UKI';
  if (/\b(belgium|benelux|luxembourg|brussels)\b/.test(s)) return 'BeLux';
  if (/\b(netherlands|dutch|holland|amsterdam)\b/.test(s)) return 'NL';
  return null;
}
function regionFromTZ(tz) {
  const s = String(tz || '').toLowerCase();
  if (s.includes('london') || s.includes('dublin')) return 'UKI';
  if (s.includes('brussels') || s.includes('luxembourg')) return 'BeLux';
  if (s.includes('amsterdam')) return 'NL';
  return null;
}
return $input.all().map((it) => {
  const w = it.json;
  const start = (w.times && w.times[0] && w.times[0].startTime) || w.startTime || null;
  const region = regionFromText(w.subject) || regionFromTZ(w.timeZone) || 'UNASSIGNED';
  return { json: {
    event_key: String(w.webinarKey || w.id || ''),
    organizer_key: String(w.organizerKey || ''),
    event_name: w.subject || w.name || null,
    activity_date: start ? String(start).slice(0, 10) : null,
    region_code: region,
    campaign_key: null
  }};
}).filter((i) => i.json.event_key && i.json.activity_date);

// Count distinct registrants per webinar using pairedItem lineage
// (works whether n8n splits the array response into items or returns it as one).
const base = $('Flatten Webinars').all();
const sets = base.map(() => new Set());
for (const it of $input.all()) {
  let idx = 0;
  const pi = it.pairedItem;
  if (typeof pi === 'number') idx = pi;
  else if (pi && typeof pi.item === 'number') idx = pi.item;
  else if (Array.isArray(pi) && pi[0] && typeof pi[0].item === 'number') idx = pi[0].item;
  const b = it.json;
  const list = Array.isArray(b) ? b
    : (b && Array.isArray(b.registrants)) ? b.registrants : (b && Array.isArray(b.data)) ? b.data
    : (b && (b.registrantKey || b.attendeeKey || b.email)) ? [b]
    : [];
  for (const a of list) { const k = a.registrantKey || a.email; if (k && sets[idx]) sets[idx].add(k); }
}
return base.map((w, i) => ({ json: { ...w.json, registrants: sets[i].size } }));

// Final rows: attendees counted from this node's input (Get Attendees) via pairedItem,
// joined onto the webinar base (which already carries registrants).
const base = $('Add Registrants').all();
const sets = base.map(() => new Set());
for (const it of $input.all()) {
  let idx = 0;
  const pi = it.pairedItem;
  if (typeof pi === 'number') idx = pi;
  else if (pi && typeof pi.item === 'number') idx = pi.item;
  else if (Array.isArray(pi) && pi[0] && typeof pi[0].item === 'number') idx = pi[0].item;
  const b = it.json;
  const list = Array.isArray(b) ? b
    : (b && Array.isArray(b.attendees)) ? b.attendees
    : (b && b._embedded && Array.isArray(b._embedded.attendees)) ? b._embedded.attendees
    : (b && (b.registrantKey || b.attendeeKey || b.email)) ? [b]
    : [];
  for (const a of list) { const k = a.registrantKey || a.attendeeKey || a.email; if (k && sets[idx]) sets[idx].add(k); }
}
return base.map((w, i) => ({ json: {
  event_key: w.json.event_key,
  event_name: w.json.event_name,
  activity_date: w.json.activity_date,
  region_code: w.json.region_code,
  campaign_key: w.json.campaign_key,
  registrants: w.json.registrants,
  attendees: sets[i].size,
  source: 'gotowebinar'
}}));
